#include <stdio.h>

#define PI 3.14159
#define MAX_STUDENTS 50
#define PRINT_MSG printf("Welcome to C Programming\n")

int main() {
    int radius = 5;
    float area = PI * radius * radius;

    printf("Area of circle: %.2f\n", area);
