#include <stdio.h>

int main() {
    const int MAX_COUNT = 100;
    const float TAX_RATE = 0.15f;
    const char DELIMITER = ',';

    printf("Maximum count: %d\n", MAX_COUNT);
    printf("Tax rate: %.2f%%\n", TAX_RATE * 100);
    printf("Delimiter: %c\n", DELIMITER);

    // const allows debugger to show variable name
    // unlike #define which has no symbol in debugger

    return 0;
}

#include <stdio.h>

// Define enum for days of week
enum days {MON=1, TUE, WED, THU, FRI, SAT, SUN};

// Define enum with custom values
enum status {FAIL=0, PASS=1, ABSENT=-1, NOT_APPLICABLE=99};

// Define enum for colors
enum color {RED, GREEN=5, BLUE};

int main() {
    enum days today = WED;
    enum status result = PASS;
    enum color primary = BLUE;

    printf("Today is day number: %d\n", today);  // 3
    printf("Result status: %d\n", result);        // 1
    printf("Blue color value: %d\n", primary);   // 6

    // Using enum in loop
    printf("\nAll days:\n");
    for (enum days d = MON; d <= SUN; d++) {
        printf("%d ", d);
    }

    return 0;
}

#include <stdio.h>

int main() {
    int x = 10;
    int y = 20;

    // 1. Pointer to constant
    const int *ptr1 = &x;
    // *ptr1 = 25;  // ERROR: cannot modify through ptr1
    ptr1 = &y;     // OK: can change pointer address

    // 2. Constant pointer
    int *const ptr2 = &x;
    *ptr2 = 25;    // OK: can modify value
    // ptr2 = &y;   // ERROR: cannot change pointer address

    // 3. Constant pointer to constant
    const int *const ptr3 = &x;
    // *ptr3 = 30;  // ERROR
    // ptr3 = &y;   // ERROR

    printf("ptr1 points to: %d\n", *ptr1);
    printf("ptr2 points to: %d\n", *ptr2);
    printf("ptr3 points to: %d\n", *ptr3);

    return 0;
}
